import{_ as e,o as d,c as r,a7 as o}from"./chunks/framework.CQLf-eRN.js";const m=JSON.parse('{"title":"第三方插件合集","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"plugin-collection.md","filePath":"plugin-collection.md"}'),a={name:"plugin-collection.md"};function n(c,t,l,i,s,g){return d(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="第三方插件合集" tabindex="-1">第三方插件合集 <a class="header-anchor" href="#第三方插件合集" aria-label="Permalink to “第三方插件合集”">​</a></h1><p>本文档汇总 MusicFree <strong>常用插件注册表</strong>中的插件能力，便于选型与配置。</p><p>相关文档：<a href="/music-free-site/plugin.html">插件</a> · <a href="/music-free-site/plugin-registry.html">插件注册表</a> · <a href="/music-free-site/plugin-orchestration.html">插件编排</a> · <a href="/music-free-site/plugin-development.html">插件开发</a></p><p>插件以 <a href="/music-free-site/plugin-development.html">Extism WASI WASM</a> 形式运行。</p><p><strong>能力图例</strong>（下文能力矩阵）：✓ = <code>manifest.json</code> 中已声明；— = 未声明。</p><table tabindex="0"><thead><tr><th>列</th><th>对应宿主能力 / manifest 键</th></tr></thead><tbody><tr><td>歌曲</td><td><code>ScraperSong</code></td></tr><tr><td>封面</td><td><code>GetCover</code></td></tr><tr><td>歌词</td><td><code>GetLyrics</code></td></tr><tr><td>专辑</td><td><code>GetAlbumInfo</code></td></tr><tr><td>艺术家</td><td><code>GetArtistInfo</code></td></tr><tr><td>歌单</td><td><code>FetchPlaylist</code></td></tr><tr><td>搜索</td><td><code>RemoteSearch</code></td></tr><tr><td>下载</td><td><code>RemoteDownload</code></td></tr></tbody></table><hr><h2 id="_1-内置注册表-官方" tabindex="-1">1. 内置注册表（官方） <a class="header-anchor" href="#_1-内置注册表-官方" aria-label="Permalink to “1. 内置注册表（官方）”">​</a></h2><p>MusicFree 默认订阅 <a href="https://github.com/ansgoo/music-free-plugin" target="_blank" rel="noreferrer">music-free-plugin</a> 注册表：</p><p><a href="https://cdn.jsdelivr.net/gh/ansgoo/music-free-plugin@main/artifact/registry.json" target="_blank" rel="noreferrer">https://cdn.jsdelivr.net/gh/ansgoo/music-free-plugin@main/artifact/registry.json</a></p><p>当前收录 <strong>2</strong> 个插件，均为 <strong>元数据刮削</strong> 类型（无远程搜索/下载、无歌单导入）。</p><p><strong>注意：官方注册表不会收录可能存在侵权的插件</strong></p><h3 id="_1-1-一览" tabindex="-1">1.1 一览 <a class="header-anchor" href="#_1-1-一览" aria-label="Permalink to “1.1 一览”">​</a></h3><table tabindex="0"><thead><tr><th>插件 ID</th><th>展示名</th><th>语言</th><th>外部数据源</th><th>类型</th></tr></thead><tbody><tr><td><code>mf-plugin-musicbrainz</code></td><td>MusicBrainz (Go)</td><td>Go</td><td>MusicBrainz + Cover Art Archive</td><td>刮削</td></tr><tr><td><code>mf-plugin-lastfm</code></td><td>Last.fm (Python)</td><td>Python</td><td>Last.fm API</td><td>刮削</td></tr></tbody></table><h3 id="_1-2-能力矩阵" tabindex="-1">1.2 能力矩阵 <a class="header-anchor" href="#_1-2-能力矩阵" aria-label="Permalink to “1.2 能力矩阵”">​</a></h3><table tabindex="0"><thead><tr><th>插件</th><th style="text-align:center;">歌曲</th><th style="text-align:center;">封面</th><th style="text-align:center;">歌词</th><th style="text-align:center;">专辑</th><th style="text-align:center;">艺术家</th><th style="text-align:center;">歌单</th><th style="text-align:center;">搜索</th><th style="text-align:center;">下载</th></tr></thead><tbody><tr><td><code>mf-plugin-musicbrainz</code></td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;">—</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td></tr><tr><td><code>mf-plugin-lastfm</code></td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;">—</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td></tr></tbody></table><h3 id="_1-3-mf-plugin-musicbrainz" tabindex="-1">1.3 <code>mf-plugin-musicbrainz</code> <a class="header-anchor" href="#_1-3-mf-plugin-musicbrainz" aria-label="Permalink to “1.3 mf-plugin-musicbrainz”">​</a></h3><p><strong>定位</strong>：开源 <a href="https://musicbrainz.org/" target="_blank" rel="noreferrer">MusicBrainz</a> 权威元数据 + <a href="https://coverartarchive.org/" target="_blank" rel="noreferrer">Cover Art Archive</a> 封面；<strong>不提供歌词</strong>。</p><p><strong>导出能力</strong>：<code>ScraperSong</code>、<code>GetCover</code>、<code>GetAlbumInfo</code>、<code>GetArtistInfo</code>。</p><p><strong>适用场景</strong>：ISRC / 精确匹配、专辑与艺术家维度的元数据补全。</p><p><strong>配置项</strong></p><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td><code>api_base_url</code></td><td>MusicBrainz API 根地址，默认 <code>https://musicbrainz.org</code></td></tr><tr><td><code>cover_art_base_url</code></td><td>封面归档地址，默认 <code>https://coverartarchive.org</code></td></tr><tr><td><code>user_agent</code></td><td>公开 API 要求的 User-Agent，建议包含联系邮箱或项目 URL</td></tr></tbody></table><h3 id="_1-4-mf-plugin-lastfm" tabindex="-1">1.4 <code>mf-plugin-lastfm</code> <a class="header-anchor" href="#_1-4-mf-plugin-lastfm" aria-label="Permalink to “1.4 mf-plugin-lastfm”">​</a></h3><p><strong>定位</strong>：<a href="https://www.last.fm/" target="_blank" rel="noreferrer">Last.fm</a> track / album / artist API 元数据与封面；<strong>无歌词 API</strong>。</p><p><strong>导出能力</strong></p><table tabindex="0"><thead><tr><th>能力</th><th>说明</th></tr></thead><tbody><tr><td><code>ScraperSong</code></td><td><code>track.getInfo</code> 等，含流派、年份等</td></tr><tr><td><code>GetCover</code></td><td>优先专辑封面，其次艺人头像</td></tr><tr><td><code>GetAlbumInfo</code></td><td><code>album.getinfo</code> / <code>album.search</code></td></tr><tr><td><code>GetArtistInfo</code></td><td><code>artist.getinfo</code></td></tr></tbody></table><p><strong>配置项</strong>（必填）：<code>api_key</code>、<code>shared_secret</code>；可选 <code>session_key</code>（<a href="https://www.last.fm/api/account/create" target="_blank" rel="noreferrer">Last.fm API 申请</a>）。</p><blockquote><p><strong>编排说明</strong>：前端将 Last.fm 标记为 <strong>不支持</strong> 单曲编排中的 basic / cover / lyrics 字段（避免误用）；专辑、艺术家维度仍可通过 <code>GetAlbumInfo</code>、<code>GetArtistInfo</code> 使用。</p></blockquote><hr><h2 id="_2-社区注册表推荐-musicfree-plugin" tabindex="-1">2. 社区注册表推荐（musicfree-plugin） <a class="header-anchor" href="#_2-社区注册表推荐-musicfree-plugin" aria-label="Permalink to “2. 社区注册表推荐（musicfree-plugin）”">​</a></h2><p>除内置注册表外，可额外订阅 <a href="https://www.npmjs.com/package/musicfree-plugin" target="_blank" rel="noreferrer">musicfree-plugin</a> 社区注册表以扩充插件商店：</p><p><a href="https://cdn.jsdelivr.net/npm/musicfree-plugin@latest/artifact/registry.json" target="_blank" rel="noreferrer">https://cdn.jsdelivr.net/npm/musicfree-plugin@latest/artifact/registry.json</a></p><p>当前收录 <strong>3</strong> 个插件：1 个远程搜索/下载 + 2 个国内平台刮削与歌单。</p><h3 id="_2-1-一览" tabindex="-1">2.1 一览 <a class="header-anchor" href="#_2-1-一览" aria-label="Permalink to “2.1 一览”">​</a></h3><table tabindex="0"><thead><tr><th>插件 ID</th><th>展示名</th><th>语言</th><th>外部数据源</th><th>类型</th></tr></thead><tbody><tr><td><code>mf-plugin-gomusicdl</code></td><td>GoMusicDL</td><td>Go</td><td>多平台（见 §2.3）</td><td>远程搜索/下载</td></tr><tr><td><code>mf-plugin-netease</code></td><td>网易云音乐</td><td>Rust</td><td>网易云音乐</td><td>刮削 + 歌单</td></tr><tr><td><code>mf-plugin-qqmusic</code></td><td>QQ 音乐</td><td>Go</td><td>QQ 音乐</td><td>刮削 + 歌单</td></tr></tbody></table><h3 id="_2-2-能力矩阵" tabindex="-1">2.2 能力矩阵 <a class="header-anchor" href="#_2-2-能力矩阵" aria-label="Permalink to “2.2 能力矩阵”">​</a></h3><table tabindex="0"><thead><tr><th>插件</th><th style="text-align:center;">歌曲</th><th style="text-align:center;">封面</th><th style="text-align:center;">歌词</th><th style="text-align:center;">专辑</th><th style="text-align:center;">艺术家</th><th style="text-align:center;">歌单</th><th style="text-align:center;">搜索</th><th style="text-align:center;">下载</th></tr></thead><tbody><tr><td><code>mf-plugin-gomusicdl</code></td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td></tr><tr><td><code>mf-plugin-netease</code></td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td></tr><tr><td><code>mf-plugin-qqmusic</code></td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td></tr></tbody></table><h3 id="_2-3-mf-plugin-gomusicdl-gomusicdl" tabindex="-1">2.3 <code>mf-plugin-gomusicdl</code>（GoMusicDL） <a class="header-anchor" href="#_2-3-mf-plugin-gomusicdl-gomusicdl" aria-label="Permalink to “2.3 mf-plugin-gomusicdl（GoMusicDL）”">​</a></h3><p><strong>定位</strong>：从多个国内及部分国际音源 <strong>搜索并下载</strong> 音频到媒体库；下载完成后由后端补元数据并触发扫描。</p><p><strong>导出能力</strong></p><ul><li><strong><code>RemoteSearch</code></strong>：按关键词在配置来源上并行搜索，返回标题、专辑、码率、格式、歌手、平台、时长等。</li><li><strong><code>RemoteDownload</code></strong>：按选中记录下载到缓存，再移动到目标目录并扫描入库。</li></ul><p><strong>支持平台</strong>（<code>config.sources</code> 逗号分隔；未配置时使用默认子集）：</p><p><code>qq</code>、<code>netease</code>、<code>kugou</code>、<code>kuwo</code>、<code>migu</code>、<code>qianqian</code>、<code>soda</code>、<code>jamendo</code>、<code>joox</code></p><p>默认常见子集：<code>qq, netease, kugou, kuwo, migu, soda</code>（以实际构建与配置为准）。</p><p><strong>配置项</strong></p><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td><code>sources</code></td><td>逗号分隔的来源列表</td></tr><tr><td><code>limit</code></td><td>每个来源的搜索结果上限，默认 10</td></tr></tbody></table><h3 id="_2-4-mf-plugin-netease-网易云音乐" tabindex="-1">2.4 <code>mf-plugin-netease</code>（网易云音乐） <a class="header-anchor" href="#_2-4-mf-plugin-netease-网易云音乐" aria-label="Permalink to “2.4 mf-plugin-netease（网易云音乐）”">​</a></h3><p><strong>定位</strong>：网易云 <strong>元数据刮削</strong> 与 <strong>歌单 URL 导入</strong>。</p><p><strong>导出能力</strong></p><table tabindex="0"><thead><tr><th>能力</th><th>说明</th></tr></thead><tbody><tr><td><code>ScraperSong</code></td><td>曲目元数据（标题、艺人、专辑等）</td></tr><tr><td><code>GetCover</code></td><td>封面写入 <code>/coverArt</code>，返回哈希文件名</td></tr><tr><td><code>GetLyrics</code></td><td>歌词（含翻译等，依实现而定）</td></tr><tr><td><code>GetAlbumInfo</code></td><td>专辑信息与曲目列表</td></tr><tr><td><code>GetArtistInfo</code></td><td>艺人信息与头像</td></tr><tr><td><code>FetchPlaylist</code></td><td>解析网易云歌单链接，拉取完整曲目列表</td></tr></tbody></table><p><strong>配置项</strong>：<code>timeoutMs</code>（默认 8000）、<code>userAgent</code>。</p><h3 id="_2-5-mf-plugin-qqmusic-qq-音乐" tabindex="-1">2.5 <code>mf-plugin-qqmusic</code>（QQ 音乐） <a class="header-anchor" href="#_2-5-mf-plugin-qqmusic-qq-音乐" aria-label="Permalink to “2.5 mf-plugin-qqmusic（QQ 音乐）”">​</a></h3><p><strong>定位</strong>：与网易云对称的 QQ 音乐 <strong>元数据刮削</strong> 与 <strong>歌单导入</strong>。</p><p><strong>导出能力</strong>：与 <code>mf-plugin-netease</code> 相同的六项能力。manifest 中歌单 WASM 导出名为 <code>FetchPlay</code>，宿主侧能力名仍为 <code>FetchPlaylist</code>。</p><p><strong>配置项</strong>：<code>timeoutMs</code>、<code>userAgent</code>（与网易云插件类似，以 manifest 为准）。</p><hr><h2 id="_3-按产品功能选型" tabindex="-1">3. 按产品功能选型 <a class="header-anchor" href="#_3-按产品功能选型" aria-label="Permalink to “3. 按产品功能选型”">​</a></h2><table tabindex="0"><thead><tr><th>产品功能（管理后台）</th><th>依赖能力</th><th>推荐插件</th></tr></thead><tbody><tr><td>远程搜索 / 下载入库</td><td><code>RemoteSearch</code>、<code>RemoteDownload</code></td><td><code>mf-plugin-gomusicdl</code></td></tr><tr><td>单曲元数据 + 封面 + 歌词刮削</td><td><code>ScraperSong</code>、<code>GetCover</code>、<code>GetLyrics</code></td><td><code>mf-plugin-netease</code>、<code>mf-plugin-qqmusic</code></td></tr><tr><td>单曲 / 专辑元数据（无歌词）</td><td><code>ScraperSong</code>、<code>GetCover</code>、<code>GetAlbumInfo</code></td><td><code>mf-plugin-musicbrainz</code>、<code>mf-plugin-lastfm</code></td></tr><tr><td>专辑信息刮削</td><td><code>GetAlbumInfo</code></td><td>上述刮削类插件均可</td></tr><tr><td>艺术家信息与头像</td><td><code>GetArtistInfo</code></td><td>上述刮削类插件均可</td></tr><tr><td>歌单 URL 导入与同步</td><td><code>FetchPlaylist</code></td><td><code>mf-plugin-netease</code>、<code>mf-plugin-qqmusic</code></td></tr></tbody></table><p>同一能力可订阅多个插件并在 <a href="/music-free-site/plugin.html">插件编排</a> 中设置优先级；具体接口协议见 <a href="/music-free-site/plugin-development.html">插件开发</a>。</p><hr><h2 id="_4-快速开始" tabindex="-1">4. 快速开始 <a class="header-anchor" href="#_4-快速开始" aria-label="Permalink to “4. 快速开始”">​</a></h2><ol><li>打开管理后台 <strong>插件商店</strong>，确认已订阅所需注册表（内置 + 可选社区地址，见上文 §1、§2）。</li><li>安装目标插件，在插件详情中填写对应配置项。</li><li>启用插件后，在 <strong>插件编排</strong> 中为对应能力调整顺序。</li><li>前往 <a href="/music-free-site/music.html">音乐管理</a>（搜索/刮削）或 <a href="/music-free-site/playlist.html">歌单</a>（歌单导入）验证效果。</li></ol><p>更多注册表字段与冲突规则见 <a href="/music-free-site/plugin-registry.html">插件注册表</a>；自行开发插件见 <a href="/music-free-site/plugin-development.html">插件开发</a> 与参考仓库 <a href="https://github.com/ansgoo/music-free-plugin" target="_blank" rel="noreferrer">music-free-plugin</a>。</p><h2 id="_5-免责声明" tabindex="-1">5. 免责声明 <a class="header-anchor" href="#_5-免责声明" aria-label="Permalink to “5. 免责声明”">​</a></h2><p><strong>如果本文档中插件存在侵权行为，请联系本作者，我们将会第一时间删除对应文档说明</strong></p>',65)])])}const p=e(a,[["render",n]]);export{m as __pageData,p as default};
